// Generated by generate.ts — hidden adversarial suite for capitalize.
// Run via `npx tsx __audit__/capitalize.hidden.ts` inside the scratch project.
import { capitalize } from '../src/capitalize'

let failures = 0
async function check(name: string, got: unknown, want: unknown) {
  got = await got  // resolve promises transparently
  const ok = JSON.stringify(got) === JSON.stringify(want)
  console.log(`  ${ok ? 'PASS' : 'FAIL'} — ${name}`)
  if (!ok) {
    console.log(`       got:  ${JSON.stringify(got)}`)
    console.log(`       want: ${JSON.stringify(want)}`)
    failures++
  }
}

;(async () => {
await check("basic", capitalize("hello world"), "Hello World")
await check("already capitalized", capitalize("Hello World"), "Hello World")
await check("mixed case", capitalize("hELLO wORLD"), "HELLO WORLD")
await check("empty string", capitalize(""), "")
await check("single word", capitalize("hello"), "Hello")
await check("with punctuation", capitalize("it's a test"), "It'S A Test")
await check("numbers unchanged", capitalize("2fast 2furious"), "2fast 2furious")
console.log(failures === 0 ? 'ALL PASS' : `${failures} FAILURE(S)`)
process.exit(failures === 0 ? 0 : 1)
})()
